import React, { useMemo } from 'react';

export default function StarField({ count = 90 }) {
  const stars = useMemo(() =>
    Array.from({ length: count }, (_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 2 + 0.5,
      delay: Math.random() * 5,
      dur: 2 + Math.random() * 3,
    })), [count]);

  return (
    <div style={{
      position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 0, overflow: 'hidden',
    }}>
      <style>{`
        @keyframes tw { 0%,100%{opacity:.12;transform:scale(1)} 50%{opacity:.85;transform:scale(1.5)} }
        .sf-star { position:absolute; border-radius:50%; background:#fff; animation:tw var(--dur) ease-in-out infinite; }
      `}</style>
      {stars.map(s => (
        <div key={s.id} className="sf-star" style={{
          left: `${s.x}%`, top: `${s.y}%`,
          width: s.size, height: s.size,
          '--dur': `${s.dur}s`,
          animationDelay: `${s.delay}s`,
        }} />
      ))}
    </div>
  );
}
